// FOR KEY SCHEDULE
uint8_t P[16] = {3,8,13,2,15,9,11,5,0,6,14,10,7,12,4,1};
uint8_t LFSR[16] = {0, 2, 4, 6, 9, 11, 13, 15, 1, 3, 5, 7, 8, 10, 12, 14};

// key related functions
void key_permutation(uint8_t key[16]){
    uint8_t tmp[16] = {0};
    for (int i = 0; i < 16; i++) tmp[i] = key[P[i]];
    for (int i = 0; i < 16; i++) key[i] = tmp[i];
}
void key_diffusion(uint8_t key[16]){
    key[3] = key[0] ^ key[3];
    key[7] = key[4] ^ key[7];
    key[11] = key[8] ^ key[11];
    key[15] = key[12] ^ key[15];
}

void key_lfsr(uint8_t key[16]){
    for (int i = 0; i < 16; i++){
        key[i] = LFSR[key[i]];
    }
}

void key_schedule(uint8_t mkey[2][16], uint8_t rkeys[13][16]){
    // initialization
    uint8_t tmp[2][16];
    for (int i = 0; i < 16; i++){
        rkeys[0][i] = mkey[0][i];
        rkeys[1][i] = mkey[1][i];
        tmp[0][i] = mkey[0][i];
        tmp[1][i] = mkey[1][i];
    }  

    for (int i = 2; i < 13; i++){
        key_diffusion(tmp[0]); // M
        key_permutation(tmp[0]); // permutation
        
        key_lfsr(tmp[1]); // lfsr
        key_diffusion(tmp[1]); // M
        key_permutation(tmp[1]); // permutation

        for (int j = 0; j < 16; j++){
            rkeys[i][j] = tmp[0][j] ^ tmp[1][j];
        }
    }

    for (uint32_t i = 0; i < 13; i++){
        printf("R%2i: ", i);
        for (uint32_t j = 0; j < 16; j++){
            printf("%x", int(rkeys[i][j]));
        }
        printf("\n");
    }
}

// main functions
void substitution(uint32_t n, uint8_t *state){
    for (uint32_t i = 0; i < 16; i++){
        state[i] = SBOX[n][15-i][state[i]];
    }
    return;
}

void inv_substitution(uint32_t n, uint8_t *state){
    for (uint32_t i = 0; i < 16; i++){
        state[i] = inv_SBOX[n][15-i][state[i]];
    }
    return;
}

void linear(uint64_t n, uint8_t *state){
    uint64_t s = 0, res = 0;
    for (uint32_t i = 0; i < 16; i++){
        s = s << 4;
        s ^= state[i];
    }

    for (uint32_t i = 0; i < 64; i++){
        if ((s >> (63-i)) & 1){
            res ^= LINEAR[n][i];
        }
    }

    for (uint32_t i = 0; i < 16; i++){
        state[i] = (res >> (60-4*i)) & 0xf;
    }
    return;
}

void inv_linear(uint64_t n, uint8_t *state){
    uint64_t s = 0, res = 0;
    for (uint32_t i = 0; i < 16; i++){
        s = s << 4;
        s ^= state[i];
    }

    for (uint32_t i = 0; i < 64; i++){
        if ((s >> (63-i)) & 1){
            res ^= inv_LINEAR[n][i];
        }
    }

    for (uint32_t i = 0; i < 16; i++){
        state[i] = (res >> (60-4*i)) & 0xf;
    }
    return;
}

void add_round_key(uint8_t *state, uint8_t key[16]){
    for (uint32_t i = 0; i < 16; i++){
        state[i] = state[i] ^ key[i];
    }
    return;
}

void enc_one_round(uint32_t n, uint8_t *state, uint8_t key[16]){
    printf("==================");
    printf("ROUND %d", n);
    printf("==================\n");

    printf("%25s","BEFORE KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    add_round_key(state,key);
    printf("%25s","AFTER KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    printf("%25s","BEFORE SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    substitution(n, state);
    printf("%25s","AFTER SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");


    printf("%25s","BEFORE LINEAR: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    linear(n, state);
    printf("%25s","AFTER LINEAR: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    return;
}

void dec_one_round(uint32_t n, uint8_t *state, uint8_t key[16]){
    printf("==================");
    printf("ROUND %d", n);
    printf("==================\n");

    printf("%25s","BEFORE INV_LINEAR: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    inv_linear(n, state);
    printf("%25s","AFTER INV_LINEAR: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    printf("%25s","BEFORE INV_SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    inv_substitution(n, state);
    printf("%25s","AFTER INV_SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    printf("%25s","BEFORE KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    add_round_key(state,key);
    printf("%25s","AFTER KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    return;
}

void encrypt(uint8_t *state, uint8_t mkey[2][16]){
    uint8_t rkeys[13][16];
    printf("ROUND KEYS\n");
    key_schedule(mkey,rkeys);
    for (uint32_t n = 0; n < 11; n++){
        enc_one_round(n, state, rkeys[n]);
    }
    printf("==================");
    printf("ROUND %d", 11);
    printf("==================\n");
    printf("%25s","BEFORE KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    add_round_key(state, rkeys[11]);
    printf("%25s","AFTER KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    printf("%25s","BEFORE SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    substitution(11, state);
    printf("%25s","AFTER SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    printf("%25s","BEFORE KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    add_round_key(state, rkeys[12]);
    printf("%25s","AFTER KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
}

void decrypt(uint8_t *state, uint8_t mkey[2][16]){
    uint8_t rkeys[13][16];
    printf("ROUND KEYS\n");
    key_schedule(mkey, rkeys);
    printf("==================");
    printf("ROUND %d", 11);
    printf("==================\n");
    printf("%25s","BEFORE KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    add_round_key(state, rkeys[12]);
    printf("%25s","AFTER KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    printf("%25s","BEFORE INV SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    inv_substitution(11, state);
    printf("%25s","AFTER INV SUBSTITUTION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    printf("%25s","BEFORE KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");
    add_round_key(state, rkeys[11]);
    printf("%25s","AFTER KEY ADDITION: ");
    for (uint32_t i = 0; i < 16; i++) printf("%x",state[i]);
    printf("\n");

    for (int n = 10; n >= 0; n--){
        dec_one_round(n,state, rkeys[n]);
    }
}

